import React from 'react';
import './MessageBubble.css';

function MessageBubble({ text, sender }) {
  return (
    <div className={`message-row ${sender}`}>
      <div className={`bubble ${sender}`}>
        {text}
      </div>
    </div>
  );
}

export default MessageBubble;
